<template>
  <view class="p-4">

    <!-- 加载状态 -->
    <view v-if="loading" class="mt-4 flex justify-center items-center">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="ml-2 text-gray-500">加载中...</text>
    </view>

    <!-- 求助渠道列表 -->
    <u-cell-group v-else>
      <u-cell
        v-for="item in channels"
        :key="item.id"
        :title="item.name"
        :label="item.desc"
        is-link
        @click="contact(item)"
      >
        <template #value>
          <u-tag 
            :text="getChannelTypeLabel(item.type)" 
            :type="getChannelTypeTag(item.type)" 
            size="mini"
          ></u-tag>
        </template>
      </u-cell>
    </u-cell-group>

    <!-- 空状态 -->
    <u-empty v-if="!loading && channels.length === 0" mode="data" text="暂无求助渠道"></u-empty>

    <!-- 模板下载 -->
    <view class="mt-4 text-center">
      <u-button type="primary" @click="downloadTemplate" :loading="downloading">
        下载求助模板
      </u-button>
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import request from '@/utils/request'

// 渠道类型
interface Channel {
  id: number
  name: string
  desc: string
  type: string
  contactValue: string
  serviceTime: string
  available: boolean
}

// 列表数据
const channels = ref<Channel[]>([])
const loading = ref(false)
const downloading = ref(false)

// 获取渠道类型标签样式
const getChannelTypeTag = (type: string) => {
  const tagMap: Record<string, any> = {
    phone: 'success',
    chat: 'primary',
    email: 'warning',
    offline: 'info' // u-view 没有 default，通常用 info 或 primary
  }
  return tagMap[type] || 'info'
}

// 获取渠道类型标签文字
const getChannelTypeLabel = (type: string) => {
  const labelMap: Record<string, string> = {
    phone: '电话',
    chat: '在线',
    email: '邮件',
    offline: '线下'
  }
  return labelMap[type] || '其他'
}

// 获取求助渠道列表
const fetchChannels = async () => {
  loading.value = true
  try {
    const res = await request.get('/api/resource/charity/channels')
    const data = res.data || res.data || {}
    channels.value = data.channels || []
  } catch (error) {
    uni.__f__('error','at pages/resource/charity/HelpChannel.vue:92','获取求助渠道失败:', error)
    channels.value = []
    uni.showToast({ title: '加载失败，请重试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 联系求助渠道
const contact = (item: Channel) => {
  // 修改：先跳转到详情页
  if (!item?.id) {
    uni.showToast({ title: '渠道信息不完整', icon: 'none' })
    return
  }
  uni.navigateTo({
    url: `/pages/resource/charity/HelpChannelDetail?id=${item.id}`
  })
}

// 下载求助模板
const downloadTemplate = async () => {
  downloading.value = true
  try {
    const res = await request.get('/api/resource/charity/channels/template')
    const data = res.data || res.data || {}

    if (data.templates && data.templates.length > 0) {
      // 如果有多个模板，显示选择弹窗
      if (data.templates.length > 1) {
        const templateList = data.templates.map((t: any) => `${t.name} (${t.size})`).join('\n')
        
        uni.showModal({
          title: '选择模板',
          content: templateList,
          confirmText: '下载全部',
          cancelText: '取消',
          success: (modalRes) => {
            if (modalRes.confirm) {
              data.templates.forEach((template: any) => {
                downloadSingleFile(template.url, template.name)
              })
              uni.showToast({ title: '下载已开始', icon: 'success' })
            }
          }
        })
      } else {
        // 只有一个模板，直接下载
        const template = data.templates[0]
        downloadSingleFile(template.url, template.name)
        uni.showToast({ title: '下载已开始', icon: 'success' })
      }
    } else {
      uni.showToast({ title: '暂无可下载模板', icon: 'none' })
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/charity/HelpChannel.vue:148','下载模板失败:', error)
    uni.showToast({ title: '下载失败，请重试', icon: 'none' })
  } finally {
    downloading.value = false
  }
}

// 辅助函数：下载单个文件
const downloadSingleFile = (url: string, name: string) => {
  // 处理相对路径
  let downloadUrl = url
  if (!url.startsWith('http')) {
    // 请根据实际 baseURL 拼接，这里假设 request.ts 中有 BASE_URL 或者此处硬编码
    // 注意：uni.downloadFile 需要合法域名
    downloadUrl = 'https://api.yourserver.com' + url 
  }

  uni.downloadFile({
    url: downloadUrl,
    success: (res) => {
      if (res.statusCode === 200) {
        uni.openDocument({
          filePath: res.tempFilePath,
          showMenu: true,
          success: () => {
            uni.__f__('log','at pages/resource/charity/HelpChannel.vue:173',`${name} 打开成功`)
          },
          fail: () => {
            uni.showToast({ title: `${name} 打开失败`, icon: 'none' })
          }
        })
      } else {
        uni.showToast({ title: `${name} 下载失败`, icon: 'none' })
      }
    },
    fail: () => {
      uni.showToast({ title: `${name} 网络请求失败`, icon: 'none' })
    }
  })
}

// 组件挂载时初始化
onMounted(() => {
  fetchChannels()
})
</script>

